static ge::graphStatus TilingFunc(gert::TilingContext* context) {
    Ca6k00355CustomTilingData tiling;
    const gert::StorageShape* x_shape = context->GetInputShape(0);
    uint32_t totalLength = x_shape->GetOriginShape().GetShapeSize();
    uint32_t N = x_shape->GetOriginShape().GetDim(0);
    uint32_t C = x_shape->GetOriginShape().GetDim(1);
    uint32_t H = x_shape->GetOriginShape().GetDim(2);
    uint32_t W = x_shape->GetOriginShape().GetDim(3);
    uint32_t spatialSize = N * H * W;

    const gert::RuntimeAttrs* attrs = context->GetAttrs();
    int32_t training = attrs->GetAttrPointer<int32_t>(0) ? *attrs->GetAttrPointer<int32_t>(0) : 0;
    float momentum = attrs->GetAttrPointer<float>(1) ? *attrs->GetAttrPointer<float>(1) : 0.1f;
    float eps = attrs->GetAttrPointer<float>(2) ? *attrs->GetAttrPointer<float>(2) : 1e-5f;

    const uint32_t align = 2048;
    uint32_t tileLength = totalLength;
    if (tileLength > 65536) {
        tileLength = (65536 / align) * align;
    }

    uint32_t blockDim = (totalLength + tileLength - 1) / tileLength;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLength);
    tiling.set_blockDim(blockDim);
    tiling.set_numChannels(C);
    tiling.set_spatialSize(spatialSize);
    tiling.set_training(training);
    tiling.set_momentum(momentum);
    tiling.set_eps(eps);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t* workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;

    return ge::GRAPH_SUCCESS;
}

